import os
from flask import Flask, request, abort
import config

app = Flask(__name__)
app.config.from_object(config.Config)

def allowed_file(filename):
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in {'jpg', 'png'}

def validate_image_header(file_stream):
    """
    Validates that the file has a valid JPEG or PNG header (magic bytes).
    Reads the first 4 bytes and resets the stream position.
    """
    header = file_stream.read(8)
    file_stream.seek(0)

    # JPEG magic bytes (FF D8 FF E0, FF D8 FF E1, etc.)
    # typically FF D8 FF
    if header.startswith(b'\xff\xd8\xff'):
        return True

    # PNG magic bytes (89 50 4E 47 0D 0A 1A 0A)
    if header.startswith(b'\x89PNG\r\n\x1a\n'):
        return True

    return False

@app.route('/upload', methods=['POST'])
def upload_file():
    if 'file' not in request.files: 
        return 'No file', 400
    file = request.files['file']

    if file and allowed_file(file.filename):
        if not validate_image_header(file.stream):
            return 'Invalid file content', 400

        file.save(os.path.join(app.config['UPLOAD_FOLDER'], file.filename))
        return 'Success', 201
    return 'Invalid', 403

if __name__ == '__main__':
    app.run(debug=True)
